"""
Toy-Check fuer invariante Unterraeume und Summenzerlegung.

Modell:
- Gruppe: A4 oder A5 als Permutationsgruppe auf n Punkten
- Darstellung: Permutationsdarstellung auf Q^n

Zusatzmodus:
- a5_geo: rotational icosahedral/dodecahedral symmetry group, isomorphic to A5.
  This is NOT the full Ih group (no inversion/reflections).
"""


# This file was *autogenerated* from the file scripts/invariant_subspaces_a4_toy.sage
from sage.all_cmdline import *   # import sage library

_sage_const_0 = Integer(0); _sage_const_1 = Integer(1); _sage_const_10 = Integer(10); _sage_const_1en8 = RealNumber('1e-8'); _sage_const_3 = Integer(3); _sage_const_1p0 = RealNumber('1.0'); _sage_const_2 = Integer(2); _sage_const_60 = Integer(60); _sage_const_5 = Integer(5); _sage_const_12 = Integer(12); _sage_const_1en6 = RealNumber('1e-6'); _sage_const_4 = Integer(4); _sage_const_1en7 = RealNumber('1e-7'); _sage_const_20260703 = Integer(20260703); _sage_const_6 = Integer(6); _sage_const_9 = Integer(9); _sage_const_1en9 = RealNumber('1e-9'); _sage_const_0p0 = RealNumber('0.0'); _sage_const_8 = Integer(8); _sage_const_7 = Integer(7); _sage_const_11 = Integer(11)
from sage.all import *
