def permutation_matrix_qn(perm, n):
    """nxn-Permutationsmatrix ueber QQ fuer eine Permutation."""
    M = matrix(QQ, n, n, _sage_const_0 )
    for i in range(_sage_const_1 , n + _sage_const_1 ):
        M[perm(i) - _sage_const_1 , i - _sage_const_1 ] = _sage_const_1 
    return M


def is_invariant_subspace(mats, basis_vectors):
    """
    Prueft Invarianz eines Unterraums span(basis_vectors) unter allen Matrizen.
    """
    if not basis_vectors:
        return True
    B = matrix(QQ, basis_vectors).transpose()
    W = B.column_space()
    for A in mats:
        for v in basis_vectors:
            if A * vector(QQ, v) not in W:
                return False
    return True


def print_subspace(name, basis_vectors):
    print(f"{name}:")
    for v in basis_vectors:
        print(f"  {tuple(v)}")


def build_sumzero_basis(n):
    """
    Basis von {x in Q^n | Summe(x)=0}: e_i - e_n fuer i=1..n-1
    """
    basis = []
    for i in range(n - _sage_const_1 ):
        v = [_sage_const_0 ] * n
        v[i] = _sage_const_1 
        v[n - _sage_const_1 ] = -_sage_const_1 
        basis.append(vector(QQ, v))
    return basis


def run_perm_case(n):
    G = AlternatingGroup(n)
    mats = [permutation_matrix_qn(g, n) for g in G.list()]

    print(f"Gruppe A{n}, |G| = {G.order()}")
    print(f"Anzahl Darstellungsoperatoren: {len(mats)}")

    one = vector(QQ, [_sage_const_1 ] * n)
    W_triv_basis = [one]
    W_sumzero_basis = build_sumzero_basis(n)

    print_subspace("W_triv (trivialer Unterraum)", W_triv_basis)
    print_subspace("W_sumzero (Summe = 0)", W_sumzero_basis)

    inv_triv = is_invariant_subspace(mats, W_triv_basis)
    inv_sumzero = is_invariant_subspace(mats, W_sumzero_basis)

    print(f"Invariant W_triv: {inv_triv}")
    print(f"Invariant W_sumzero: {inv_sumzero}")

    V = VectorSpace(QQ, n)
    W_triv = span(W_triv_basis)
    W_sumzero = span(W_sumzero_basis)

    inter_dim = W_triv.intersection(W_sumzero).dimension()
    sum_space = W_triv + W_sumzero
    sum_dim = sum_space.dimension()

    print(f"dim(W_triv ∩ W_sumzero) = {inter_dim}")
    print(f"dim(W_triv + W_sumzero) = {sum_dim}")
    print(f"dim(V) = {V.dimension()}")
    print(
        f"Direktsummen-Check (dim={n} und Schnitt=0): "
        f"{sum_dim == n and inter_dim == _sage_const_0 }"
    )

    inv_sum = is_invariant_subspace(mats, sum_space.basis())
    print(f"Invariant der Summe W_triv + W_sumzero: {inv_sum}")


def _round_key(v, digits=_sage_const_10 ):
    return tuple(round(float(x), digits) for x in v)


def _vertex_index_map(vertices):
    return {_round_key(v): i for i, v in enumerate(vertices)}


def _nearest_vertex_index(v, vertices, tol=_sage_const_1en8 ):
    best_i = None
    best_d = None
    for i, w in enumerate(vertices):
        d = (v - w).norm()
        if best_d is None or d < best_d:
            best_d = d
            best_i = i
    if best_d is not None and best_d < tol:
        return best_i
    return None


def _perm_from_images(images):
    # Sage permutations are 1-based
    return Permutation([i + _sage_const_1  for i in images])


def _perm_matrix_qn_from_images(images, n):
    M = matrix(QQ, n, n, _sage_const_0 )
    for i, j in enumerate(images):
        M[j, i] = _sage_const_1 
    return M


def _rotation_from_base_to_target(B, T):
    return T * B.inverse()


def _is_rotation(M, tol=_sage_const_1en8 ):
    I = identity_matrix(RDF, _sage_const_3 )
    ortho = (M.transpose() * M - I).norm() < tol
    det_ok = abs(M.det() - _sage_const_1p0 ) < tol
    return ortho and det_ok


def _images_under_rotation(M, vertices, tol=_sage_const_1en8 ):
    images = []
    for v in vertices:
        w = M * v
        idx = _nearest_vertex_index(w, vertices, tol=tol)
        if idx is None:
            return None
        images.append(idx)
    # ensure permutation
    if len(set(images)) != len(vertices):
        return None
    return images


def _generate_rotation_candidates(vertices):
    # fix a linearly independent base triple
    base = [vertices[_sage_const_0 ], vertices[_sage_const_1 ], vertices[_sage_const_2 ]]
    if matrix(RDF, _sage_const_3 , _sage_const_3 , [x for v in base for x in v]).det() == _sage_const_0 :
        raise RuntimeError("Base triple is linearly dependent.")
    B = matrix(RDF, _sage_const_3 , _sage_const_3 , [x for v in base for x in v]).transpose()

    rot_by_perm = {}
    for i, j, k in it_permutations(range(len(vertices)), int(_sage_const_3 )):
        T = matrix(RDF, _sage_const_3 , _sage_const_3 , [x for v in [vertices[i], vertices[j], vertices[k]] for x in v]).transpose()
        if abs(T.det()) < _sage_const_1en8 :
            continue
        M = _rotation_from_base_to_target(B, T)
        if not _is_rotation(M):
            continue
        images = _images_under_rotation(M, vertices)
        if images is None:
            continue
        key = tuple(images)
        if key not in rot_by_perm:
            rot_by_perm[key] = M
    return rot_by_perm


def _find_generators_of_order_60(rot_perm_keys):
    keys = list(rot_perm_keys)
    id_key = tuple(range(len(keys[_sage_const_0 ])))
    perms = [_perm_from_images(k) for k in keys if k != id_key]
    for p in perms:
        G = PermutationGroup([p])
        if G.order() == _sage_const_60 :
            return [p], G
    for a in range(len(perms)):
        for b in range(a + _sage_const_1 , len(perms)):
            G = PermutationGroup([perms[a], perms[b]])
            if G.order() == _sage_const_60 :
                return [perms[a], perms[b]], G
    return None, None


def build_a5_geo_data():
    # Icosahedron vertices with golden ratio
    phi = (_sage_const_1  + sqrt(RDF(_sage_const_5 ))) / _sage_const_2 
    verts = []
    for s1 in (-_sage_const_1 , _sage_const_1 ):
        for s2 in (-_sage_const_1 , _sage_const_1 ):
            verts.append(vector(RDF, [_sage_const_0 , s1, s2 * phi]))
            verts.append(vector(RDF, [s1, s2 * phi, _sage_const_0 ]))
            verts.append(vector(RDF, [s1 * phi, _sage_const_0 , s2]))

    # Deduplicate (there should be exactly 12)
    uniq = {}
    for v in verts:
        uniq[_round_key(v)] = v
    vertices = list(uniq.values())
    if len(vertices) != _sage_const_12 :
        raise RuntimeError(f"Expected 12 vertices, got {len(vertices)}")

    rot_by_perm = _generate_rotation_candidates(vertices)
    rot_perms = list(rot_by_perm.keys())
    n = len(vertices)

    if not rot_perms:
        raise RuntimeError("No geometric rotation symmetries found.")

    # Group from all found rotations
    all_group = PermutationGroup([_perm_from_images(p) for p in rot_perms])
    all_order = all_group.order()

    gens, gen_group = _find_generators_of_order_60(rot_perms)
    if gen_group is None:
        raise RuntimeError("Could not find a small generator set of order 60.")

    # Permutation representation on Q^12 for selected generators
    gen_images = []
    for g in gens:
        # convert Sage permutation back to image tuple
        # g(i+1) is image in 1..n
        gen_images.append(tuple(g(i + _sage_const_1 ) - _sage_const_1  for i in range(n)))
    mats = [_perm_matrix_qn_from_images(img, n) for img in gen_images]

    return {
        "vertices": vertices,
        "n": n,
        "all_group": all_group,
        "all_order": all_order,
        "gens": gens,
        "gen_group": gen_group,
        "mats": mats,
    }


def run_a5_geo_case():
    data = build_a5_geo_data()
    n = data["n"]
    all_order = data["all_order"]
