def _character_decomposition_data(G, n):
    reps = G.conjugacy_classes_representatives()
    class_sizes = [G.conjugacy_class(r).cardinality() for r in reps]
    class_orders = [r.order() for r in reps]
    fixpoints = [sum(_sage_const_1  for i in range(_sage_const_1 , n + _sage_const_1 ) if r(i) == i) for r in reps]
    perm_char = fixpoints

    CT = G.character_table()  # rows: irreducible characters, cols: conjugacy classes
    n_irred = CT.nrows()
    n_classes = CT.ncols()
    if n_classes != len(reps):
        raise RuntimeError("Character table class count mismatch.")

    mults = []
    degrees = [int(CT[i, _sage_const_0 ]) for i in range(n_irred)]
    for i in range(n_irred):
        total = _sage_const_0 
        for j in range(n_classes):
            total += class_sizes[j] * perm_char[j] * CT[i, j].conjugate()
        m = total / G.order()
        m_c = complex(CC(m))
        if abs(m_c.imag) > _sage_const_1en8 :
            raise RuntimeError(f"Non-real multiplicity encountered: {m}")
        m_int = int(round(m_c.real))
        if abs(m_c.real - m_int) > _sage_const_1en8 :
            raise RuntimeError(f"Non-integral multiplicity encountered: {m}")
        mults.append(m_int)

    dim_sum = sum(mults[i] * degrees[i] for i in range(n_irred))
    trivial_mult = mults[_sage_const_0 ] if mults else None

    return {
        "reps": reps,
        "class_sizes": class_sizes,
        "class_orders": class_orders,
        "fixpoints": fixpoints,
        "perm_char": perm_char,
        "character_table": CT,
        "degrees": degrees,
        "multiplicities": mults,
        "dim_sum": dim_sum,
        "trivial_mult": trivial_mult,
    }


def run_a5_geo_projectors_case():
    data = build_a5_geo_data()
    G = data["gen_group"]
    n = data["n"]
    decomp = _character_decomposition_data(G, n)
    CT = decomp["character_table"]
    degrees = decomp["degrees"]
    mults = decomp["multiplicities"]
    dim_sum = decomp["dim_sum"]
    trivial_mult = decomp["trivial_mult"]

    # class index for each group element
    classes = G.conjugacy_classes()
    class_index = {}
    for idx, cl in enumerate(classes):
        for g in cl:
            class_index[g] = idx

    K = CyclotomicField(_sage_const_5 )
    elems = G.list()
    rho = {}
    for g in elems:
        img = tuple(g(i + _sage_const_1 ) - _sage_const_1  for i in range(n))
        rho[g] = matrix(K, _perm_matrix_qn_from_images(img, n))

    # only irreducibles that appear in this representation
    irred_indices = [i for i, m in enumerate(mults) if m > _sage_const_0 ]
    projectors = []
    ranks = []
    for i in irred_indices:
        P = matrix(K, n, n, _sage_const_0 )
        for g in elems:
            j = class_index[g.inverse()]
            chi = K(CT[i, j])
            P += chi * rho[g]
        P *= K(degrees[i]) / K(G.order())
        projectors.append(P)
        ranks.append(P.rank())

    # checks
    idempotence_ok = all((P * P) == P for P in projectors)
    orthogonality_ok = True
    zeroM = matrix(K, n, n, _sage_const_0 )
    for a in range(len(projectors)):
        for b in range(len(projectors)):
            if a == b:
                continue
            if projectors[a] * projectors[b] != zeroM:
                orthogonality_ok = False
                break
        if not orthogonality_ok:
            break
    sum_projector = matrix(K, n, n, _sage_const_0 )
    for P in projectors:
        sum_projector += P
    identity_ok = sum_projector == identity_matrix(K, n)

    rank_targets = [degrees[i] * mults[i] for i in irred_indices]
    rank_check = ranks == rank_targets
    decomposition_ok = (dim_sum == n and trivial_mult == _sage_const_1 )

    print("mode: a5_geo_projectors")
    print("a5_geo = rotational icosahedral/dodecahedral symmetry group, isomorphic to A5")
    print("note: this is not the full Ih group")
    print(f"group order: {G.order()}")
    print(f"decomposition multiplicities: {mults}")
    print(f"decomposition degrees: {degrees}")
    print(f"decomposition used (indices): {irred_indices}")
    print(f"decomposition check (dim=12 & trivial mult=1): {decomposition_ok}")
    print(f"projector idempotence: {idempotence_ok}")
    print(f"projector orthogonality: {orthogonality_ok}")
    print(f"projector ranks: {ranks}")
    print(f"projector rank targets: {rank_targets}")
    print(f"rank check: {rank_check}")
    print(f"sum of projectors = identity: {identity_ok}")


def _build_a5_geo_projectors():
    data = build_a5_geo_data()
    G = data["gen_group"]
    n = data["n"]
    decomp = _character_decomposition_data(G, n)
    CT = decomp["character_table"]
    degrees = decomp["degrees"]
    mults = decomp["multiplicities"]

    classes = G.conjugacy_classes()
    class_index = {}
    for idx, cl in enumerate(classes):
        for g in cl:
            class_index[g] = idx

    K = CyclotomicField(_sage_const_5 )
    elems = G.list()
    rho = {}
    for g in elems:
        img = tuple(g(i + _sage_const_1 ) - _sage_const_1  for i in range(n))
        rho[g] = matrix(K, _perm_matrix_qn_from_images(img, n))

    irred_indices = [i for i, m in enumerate(mults) if m > _sage_const_0 ]
    projectors = []
    for i in irred_indices:
        P = matrix(K, n, n, _sage_const_0 )
        for g in elems:
            j = class_index[g.inverse()]
            chi = K(CT[i, j])
            P += chi * rho[g]
        P *= K(degrees[i]) / K(G.order())
        projectors.append(P)

    return {
        "data": data,
        "decomp": decomp,
        "K": K,
        "irred_indices": irred_indices,
        "projectors": projectors,
    }


def _energy(v):
    return (v.dot_product(v))


def _mode_energies(v, projectors):
    comps = [P * v for P in projectors]
    return [CC(_energy(c)).real() for c in comps], comps


def _find_antipodal_pair(vertices, tol=_sage_const_1en8 ):
    for i, v in enumerate(vertices):
        for j, w in enumerate(vertices):
            if i == j:
                continue
            if (v + w).norm() < tol:
                return i, j
    raise RuntimeError("No antipodal vertex pair found.")


def _all_antipodal_pairs(vertices, tol=_sage_const_1en8 ):
    pairs = []
    used = set()
    for i, v in enumerate(vertices):
        if i in used:
            continue
        found = None
        for j, w in enumerate(vertices):
            if i == j or j in used:
                continue
            if (v + w).norm() < tol:
                found = j
                break
        if found is None:
            raise RuntimeError("Could not complete antipodal pairing.")
        pairs.append((i, found))
        used.add(i)
        used.add(found)
    return pairs


def _icosahedron_adjacency(vertices, tol=_sage_const_1en8 ):
    n = len(vertices)
    dmin = None
    for i in range(n):
        for j in range(i + _sage_const_1 , n):
            d = (vertices[i] - vertices[j]).norm()
            if d > tol and (dmin is None or d < dmin):
                dmin = d
    if dmin is None:
        raise RuntimeError("Could not determine edge length.")

    adj = {i: set() for i in range(n)}
    for i in range(n):
        for j in range(i + _sage_const_1 , n):
            d = (vertices[i] - vertices[j]).norm()
            if abs(d - dmin) < _sage_const_1en6 :
                adj[i].add(j)
                adj[j].add(i)
    return adj


def _connected_triple_cover(vertices):
    """
    Deterministic toy embedding with 4 connected triples in the edge graph.
    """
    adj = _icosahedron_adjacency(vertices)
    unused = set(range(len(vertices)))
    groups = []

    while len(groups) < _sage_const_4  and unused:
        # deterministic seed: smallest index
        a = min(unused)
        nb = sorted([x for x in adj[a] if x in unused])
        if len(nb) < _sage_const_2 :
            # fallback: any two remaining
            rem = sorted(unused - {a})
            if len(rem) < _sage_const_2 :
                break
            b, c = rem[_sage_const_0 ], rem[_sage_const_1 ]
        else:
            b = nb[_sage_const_0 ]
            # choose c adjacent to a and preferably to b as well
            candidates = [x for x in nb[_sage_const_1 :] if b in adj[x]]
            c = candidates[_sage_const_0 ] if candidates else nb[_sage_const_1 ]
        g = [a, b, c]
        for x in g:
            if x in unused:
                unused.remove(x)
        groups.append(g)

    if len(groups) != _sage_const_4 :
        raise RuntimeError("Could not build 4 connected triples for face-neighbor toy embedding.")
    return groups


def _vector_from_groups(groups, order_labels, n):
    code = {"A": _sage_const_3 , "B": _sage_const_2 , "C": _sage_const_1 , "E": _sage_const_0 }
    vals = [_sage_const_0 ] * n
    for gi, idxs in enumerate(groups):
        label = order_labels[gi]
        for idx in idxs:
            vals[idx] = code[label]
    return vector(QQ, vals)


def _center_vector(v):
    n = len(v)
    ones = vector(QQ, [_sage_const_1 ] * n)
    mean_v = QQ(sum(v)) / QQ(n)
    return vector(QQ, list(v - mean_v * ones))


def run_a5_geo_mode_fingerprints_case():
    payload = _build_a5_geo_projectors()
    data = payload["data"]
    K = payload["K"]
    irred_indices = payload["irred_indices"]
    projectors = payload["projectors"]
    n = data["n"]

    # helper to create vectors in K^n
    def vk(entries):
        return vector(K, entries)

    ones = vk([_sage_const_1 ] * n)
    e0 = vk([_sage_const_1 ] + [_sage_const_0 ] * (n - _sage_const_1 ))

    i, j = _find_antipodal_pair(data["vertices"])
    antipodal = vk([_sage_const_1  if k == i else (-_sage_const_1  if k == j else _sage_const_0 ) for k in range(n)])

    rnd = vector(QQ, [_sage_const_2 , -_sage_const_1 , _sage_const_3 , -_sage_const_2 , _sage_const_0 , _sage_const_1 , -_sage_const_3 , _sage_const_4 , -_sage_const_4 , _sage_const_2 , -_sage_const_1 , -_sage_const_1 ])  # sum = 0
    random_sumzero = vk(list(rnd))

    tests = [
        ("all_ones_barycentric", ones),
        ("single_vertex_indicator", e0),
        ("antipodal_pair_difference", antipodal),
        ("random_rational_sumzero", random_sumzero),
    ]

    print("mode: a5_geo_mode_fingerprints")
    print("a5_geo = rotational icosahedral/dodecahedral symmetry group, isomorphic to A5")
    print("note: this is not the full Ih group")
    print(f"group order: {data['gen_group'].order()}")
    print(f"projector components (irred indices): {irred_indices}")

    for name, v in tests:
        energies, comps = _mode_energies(v, projectors)
        total_energy = CC(_energy(v)).real()
        recon = sum(comps, vector(K, [_sage_const_0 ] * n))
        recon_ok = (recon == v)
        energy_ok = abs(sum(energies) - total_energy) < _sage_const_1en7 
        print(f"--- test: {name} ---")
        print(f"sum(v) = {sum(v)}")
        print(f"energies by mode: {energies}")
        print(f"total energy: {total_energy}")
        print(f"reconstruction ok: {recon_ok}")
        print(f"energy sum ok: {energy_ok}")


def _build_symbol_vector(pattern_labels, n):
    """
    Baut einen toy-Signaturvektor aus Labeln (A,B,C,E) mit
    defensiver numerischer Kodierung.
    """
    code = {"A": _sage_const_3 , "B": _sage_const_2 , "C": _sage_const_1 , "E": _sage_const_0 }
    vals = [code[pattern_labels[i % len(pattern_labels)]] for i in range(n)]
    return vector(QQ, vals)


def run_a5_geo_eabc_signature_modes_case():
    payload = _build_a5_geo_projectors()
    data = payload["data"]
    K = payload["K"]
    irred_indices = payload["irred_indices"]
    projectors = payload["projectors"]
    n = data["n"]

    # Defensives toy embedding: zyklische Labelzuweisung ueber Vertex-Indizes.
    v_abce_raw = _build_symbol_vector(["A", "B", "C", "E"], n)
    v_ceab_raw = _build_symbol_vector(["C", "E", "A", "B"], n)

    # Zentrierung (sum-zero) fuer Modenvergleich ohne dominanten trivialen Shift.
    ones = vector(QQ, [_sage_const_1 ] * n)
    mean_abce = QQ(sum(v_abce_raw)) / QQ(n)
    mean_ceab = QQ(sum(v_ceab_raw)) / QQ(n)
    v_abce = vector(QQ, list(v_abce_raw - mean_abce * ones))
    v_ceab = vector(QQ, list(v_ceab_raw - mean_ceab * ones))

    vectors = [
        ("ABCE_raw", vector(K, list(v_abce_raw))),
        ("CEAB_raw", vector(K, list(v_ceab_raw))),
        ("ABCE_centered", vector(K, list(v_abce))),
        ("CEAB_centered", vector(K, list(v_ceab))),
    ]

    print("mode: a5_geo_eabc_signature_modes")
    print("a5_geo = rotational icosahedral/dodecahedral symmetry group, isomorphic to A5")
    print("note: this is not the full Ih group")
    print("embedding note: toy cyclic label-to-vertex map (not canonical geometric EABC map)")
    print(f"group order: {data['gen_group'].order()}")
    print(f"projector components (irred indices): {irred_indices}")

    energy_map = {}
    for name, v in vectors:
        energies, comps = _mode_energies(v, projectors)
        total_energy = CC(_energy(v)).real()
        recon = sum(comps, vector(K, [_sage_const_0 ] * n))
        recon_ok = (recon == v)
        energy_ok = abs(sum(energies) - total_energy) < _sage_const_1en7 
        energy_map[name] = energies
        print(f"--- test: {name} ---")
        print(f"sum(v) = {sum(v)}")
        print(f"energies by mode: {energies}")
        print(f"total energy: {total_energy}")
        print(f"reconstruction ok: {recon_ok}")
        print(f"energy sum ok: {energy_ok}")

    # Chiralitaetsdiagnostik auf den zentrierten Vektoren (3 vs 3')
    e_abce = energy_map["ABCE_centered"]
    e_ceab = energy_map["CEAB_centered"]
    # mode ordering from decompose run: [1,3,3',5] (indices [0,1,2,4])
    d3 = e_abce[_sage_const_1 ] - e_ceab[_sage_const_1 ]
    d3p = e_abce[_sage_const_2 ] - e_ceab[_sage_const_2 ]
    print("--- comparison: centered ABCE vs CEAB ---")
    print(f"delta energy in 3-mode: {d3}")
    print(f"delta energy in 3'-mode: {d3p}")


def run_a5_geo_eabc_embedding_sweep_case():
    payload = _build_a5_geo_projectors()
